interface.definition:
a!localVariables(
  local!prisonId: property(
    #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1527068"(
      user: loggedInUser(),
      fields: #"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/cce64326-22d6-4079-a39f-cb5e0292e234"
    ),
    "data",null
  )[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/cce64326-22d6-4079-a39f-cb5e0292e234"],
  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_billboardLayout_v1"(
      backgroundMedia: #"SYSTEM_SYSRULES_documentImage"(
        document: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1069318"
      ),
      backgroundColor: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068602",
      height: "EXTRA_SHORT",
      marginBelow: "NONE",
      overlay: #"SYSTEM_SYSRULES_fullOverlay"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(),
          #"SYSTEM_SYSRULES_sideBySideLayout"(
            items: {
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: {
                        #"urn:appian:translation-string:v1:a7884a99-3410-4d2b-bde0-08d4bd236931"
                      },
                      size: "LARGE"
                    )
                  }
                )
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(labelPosition: "COLLAPSED", value: {})
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: a!localVariables(
                    local!now: a!refreshVariable(value: now(), refreshInterval: 1),
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: text(local!now, "dddd, dd. mmmm hh:mm"),
                      size: "LARGE"
                    )
                  )
                ),
                width: "MINIMIZE"
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1076413"
                  ),
                  size: "TINY",
                  align: "END"
                ),
                width: "MINIMIZE"
              )
            }
          )
        },
        style: "SEMI_DARK"
      )
    ),
    isHeaderFixed: true,
    contents: {
      #"SYSTEM_SYSRULES_recordActionField_v1"(
        actions: #"SYSTEM_SYSRULES_recordActionItem"(
          action: #"urn:appian:record-action:v1:fa952da3-a305-45ce-924b-89ca2dab3222/c9bf6c29-f136-4ecd-9006-6c13d140adbb"
        ),
        style: "CALL_TO_ACTION",
        openActionsIn: "DIALOG"
      ),
      #"SYSTEM_SYSRULES_cardLayout"(
        showBorder: false,
        showShadow: true,
        shape: "SEMI_ROUNDED",
        padding: "LESS",
        contents: {
          #"SYSTEM_SYSRULES_gridField_v3"(
            labelPosition: "COLLAPSED",
            data: #"SYSTEM_SYSRULES_recordData"(
              recordType: #"urn:appian:record-type:v1:fa952da3-a305-45ce-924b-89ca2dab3222",
              filters: if(
                #"urn:appian:function:v1:a:isusermemberofgroup?okey=a!isUserMemberOfGroup"(
                  username: loggedInUser(),
                  groups: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418982"
                ),
                {},
                #"SYSTEM_SYSRULES_queryFilter"(
                  applyWhen: a!isNotNullOrEmpty(local!prisonId),
                  field: #"urn:appian:record-field:v1:fa952da3-a305-45ce-924b-89ca2dab3222/e1088bb7-c94e-425c-8e45-84e65157b5eb",
                  operator: "in",
                  value: local!prisonId
                )
              ),

            ),
            columns: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1530911"(),
            pageSize: 20,
            refreshAfter: "RECORD_ACTION",
            userFilters: {
              #"urn:appian:user-filter:v1:fa952da3-a305-45ce-924b-89ca2dab3222/a83632d1-cc77-4e03-aeb2-a02a9145db0a",
              #"urn:appian:user-filter:v1:fa952da3-a305-45ce-924b-89ca2dab3222/a83ac0be-7d98-4813-88cc-1c5428bca4f5",
              #"urn:appian:user-filter:v1:fa952da3-a305-45ce-924b-89ca2dab3222/1c59c23d-af4e-4346-bdc6-a0306806139e"
            },

          )
        }
      )
    }
  )
)
